55		common.UpdateName(deployment, trustManagerDeploymentName)
56		common.UpdateNamespace(deployment, operandNamespace)
57		common.UpdateResourceLabels(deployment, resourceLabels)
58		updateResourceAnnotations(deployment, resourceAnnotations)
