90	// validateDeploymentManifest checks that the bindata deployment contains the
91	// expected container and TLS volume. Without these, the update helpers silently
92	// no-op and the operator would apply a deployment with stale defaults.
93	func validateDeploymentManifest(deployment *appsv1.Deployment) error {
94		hasContainer := false
95		for _, c := range deployment.Spec.Template.Spec.Containers {
96			if c.Name == trustManagerContainerName {
97				hasContainer = true
98				break
99			}
100		}
101		if !hasContainer {
102			return fmt.Errorf("deployment manifest missing required container %q", trustManagerContainerName)
103		}
104	
105		hasVolume := false
106		for _, v := range deployment.Spec.Template.Spec.Volumes {
107			if v.Name == tlsVolumeName && v.Secret != nil {
108				hasVolume = true
109				break
110			}
111		}
112		if !hasVolume {
113			return fmt.Errorf("deployment manifest missing required secret volume %q", tlsVolumeName)
114		}
115	
116		return nil
117	}
